      if (bootPhase < bootSequence.length) {
        setOutput(prev => [...prev, { type: 'boot', text: bootSequence[bootPhase].text }]);
        timeout = setTimeout(() => {
          setBootPhase(prev => prev + 1);
        }, bootSequence[bootPhase].delay);
      } else {
        setTerminalReady(true);
        setOutput(prev => [...prev, { type: 'system', text: 'Welcome to Zenu Terminal v2.0' }]);
        setOutput(prev => [...prev, { type: 'system', text: 'Type "help" for available commands.' }]);
      }
    };
    runBootSequence();
    return () => clearTimeout(timeout);
  }, [bootPhase]);

  // Matrix rain effect
  useEffect(() => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    canvas.id = 'matrix-canvas';
    canvas.style.position = 'fixed';
    canvas.style.top = '0';
    canvas.style.left = '0';
    canvas.style.width = '100%';
    canvas.style.height = '100%';
    canvas.style.zIndex = '1';
    canvas.style.opacity = '0.15';
    document.body.appendChild(canvas);

    const matrix = document.getElementById('matrix');
    if (matrix) {
      matrix.appendChild(canvas);
    }

    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789@#$%^&*()';
    const fontSize = 14;
    const columns = canvas.width / fontSize;
    const drops = Array(Math.floor(columns)).fill(1);

    const drawMatrix = () => {
      ctx.fillStyle = 'rgba(0, 0, 0, 0.05)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#0F0';
      ctx.font = fontSize + 'px monospace';

      for (let i = 0; i < drops.length; i++) {
        const text = chars[Math.floor(Math.random() * chars.length)];
        ctx.fillText(text, i * fontSize, drops[i] * fontSize);

        if (drops[i] * fontSize > canvas.height && Math.random() > 0.975) {
          drops[i] = 0;
        }
        drops[i]++;
      }
    };

    const matrixInterval = setInterval(drawMatrix, 50);

    return () => {
      clearInterval(matrixInterval);
      window.removeEventListener('resize', resizeCanvas);
      if (canvas.parentNode) {
        canvas.parentNode.removeChild(canvas);
      }
    };
  }, []);

  useEffect(() => {
    if (terminalRef.current) {
      terminalRef.current.scrollTop = terminalRef.current.scrollHeight;
    }
  }, [output]);

  const executeCommand = (cmd) => {
    const trimmedCmd = cmd.trim().toLowerCase();
    const parts = cmd.trim().split(' ');
    const command = parts[0].toLowerCase();
    const args = parts.slice(1);

    setCommandHistory(prev => [...prev, cmd]);
    setOutput(prev => [...prev, { type: 'input', text: `zenu@dev:~$ ${cmd}` }]);

    switch (command) {
      case 'help':
        setOutput(prev => [...prev, { 
          type: 'output', 
          text: `Available commands:
  help     - Show this help message
  ls       - List directory contents
  cat      - Display file contents
  whoami   - Display current user
  clear    - Clear terminal
  date     - Show current date/time
  uname    - System information
  matrix   - Toggle Matrix effect
  neofetch - System info display` 
        }]);
        break;
      case 'ls':
        setOutput(prev => [...prev, { type: 'output', text: 'tech-stack.txt  experience.log  projects/  contact/  about.txt' }]);
        break;
      case 'cat':
        if (args.length === 0) {
          setOutput(prev => [...prev, { type: 'error', text: 'cat: missing file operand' }]);
        } else {
          const filePath = args[0];
          if (fileSystem[`~/${filePath}`]) {
            setOutput(prev => [...prev, { type: 'output', text: fileSystem[`~/${filePath}`].content }]);
          } else {
            setOutput(prev => [...prev, { type: 'error', text: `cat: ${filePath}: No such file or directory` }]);
          }
        }
        break;
      case 'whoami':
        setOutput(prev => [...prev, { type: 'output', text: 'Hamzah Mohandeszadeh (Zenu)' }]);
        break;
      case 'clear':
        setOutput([]);
        break;
      case 'date':
        setOutput(prev => [...prev, { type: 'output', text: new Date().toString() }]);
        break;
      case 'uname':
        setOutput(prev => [...prev, { type: 'output', text: 'ZenuOS 2.0.0 x86_64' }]);
        break;
      case 'neofetch':
        setOutput(prev => [...prev, { 
          type: 'neofetch',
          text: `
        ‚Ėą‚Ėą‚ēó    ‚Ėą‚Ėą‚ēó‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēó‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēó  ‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēó ‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēó
        ‚Ėą‚Ėą‚ēĎ    ‚Ėą‚Ėą‚ēĎ‚Ėą‚Ėą‚ēĒ‚ēź‚ēź‚ēź‚ēź‚ēĚ‚Ėą‚Ėą‚ēĒ‚ēź‚ēź‚Ėą‚Ėą‚ēó‚Ėą‚Ėą‚ēĒ‚ēź‚ēź‚ēź‚Ėą‚Ėą‚ēó‚Ėą‚Ėą‚ēĒ‚ēź‚ēź‚ēź‚ēź‚ēĚ
        ‚Ėą‚Ėą‚ēĎ ‚Ėą‚ēó ‚Ėą‚Ėą‚ēĎ‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēó  ‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēĒ‚ēĚ‚Ėą‚Ėą‚ēĎ   ‚Ėą‚Ėą‚ēĎ‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēó
        ‚Ėą‚Ėą‚ēĎ‚Ėą‚Ėą‚Ėą‚ēó‚Ėą‚Ėą‚ēĎ‚Ėą‚Ėą‚ēĒ‚ēź‚ēź‚ēĚ  ‚Ėą‚Ėą‚ēĒ‚ēź‚ēź‚Ėą‚Ėą‚ēó‚Ėą‚Ėą‚ēĎ   ‚Ėą‚Ėą‚ēĎ‚ēö‚ēź‚ēź‚ēź‚ēź‚Ėą‚Ėą‚ēĎ
        ‚ēö‚Ėą‚Ėą‚Ėą‚ēĒ‚Ėą‚Ėą‚Ėą‚ēĒ‚ēĚ‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēó‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēĒ‚ēĚ‚ēö‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēĒ‚ēĚ‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚Ėą‚ēĎ
         ‚ēö‚ēź‚ēź‚ēĚ‚ēö‚ēź‚ēź‚ēĚ ‚ēö‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēĚ‚ēö‚ēź‚ēź‚ēź‚ēź‚ēź‚ēĚ  ‚ēö‚ēź‚ēź‚ēź‚ēź‚ēź‚ēĚ ‚ēö‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēĚ

        Hamzah Mohandeszadeh (Zenu)
        ---------------------------
        OS: ZenuOS 2.0.0
        Host: Quantum Terminal
        Kernel: 5.15.0-zenu
        Uptime: ${Math.floor(Math.random() * 100)} days
        Shell: zsh 5.9
        Resolution: 900x600
        Theme: Dark Matte
        CPU: Quantum Core i9 @ 5.2GHz
        Memory: 64GB / 128GB
        `
        }]);
        break;
      default:
        setOutput(prev => [...prev, { type: 'error', text: `Command not found: ${command}. Type 'help' for available commands.` }]);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && currentInput.trim()) {
      executeCommand(currentInput);
      setCurrentInput('');
    }
  };

  return (
    <div className="terminal-container">
      <div className="matrix-background" id="matrix"></div>
      <div className="crt-overlay"></div>
      <div className="scanlines"></div>
      <div className="terminal-window">
        <div className="terminal-header">
          <div className="terminal-buttons">
            <div className="terminal-button close"></div>
            <div className="terminal-button minimize"></div>
            <div className="terminal-button maximize"></div>
          </div>
          <div className="terminal-title">zenu@dev:~ - Zenu Terminal</div>
        </div>
        <div className="terminal-body" ref={terminalRef}>
          {output.map((line, index) => (
            <div key={index} className={`terminal-line ${line.type}`}>
              {line.type === 'boot' && <span className="boot-text">{line.text}</span>}
              {line.type === 'system' && <span className="system-text">{line.text}</span>}
              {line.type === 'input' && <span className="input-text">{line.text}</span>}
              {line.type === 'output' && <pre className="output-text">{line.text}</pre>}
              {line.type === 'error' && <span className="error-text">{line.text}</span>}
              {line.type === 'neofetch' && <pre className="neofetch-text">{line.text}</pre>}
            </div>
          ))}
          {terminalReady && (
            <div className="input-line">
              <span className="prompt">zenu@dev:~$</span>
              <input
                type="text"
                className="command-input"
                value={currentInput}
                onChange={(e) => setCurrentInput(e.target.value)}
                onKeyDown={handleKeyDown}
                autoFocus
                autoComplete="off"
              />
              <span className="cursor">‚Ėą</span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;
